package com.seaquake6324.civitas.application;
import static org.junit.jupiter.api.Assertions.*;import com.seaquake6324.civitas.domain.*;import java.util.*;import org.junit.jupiter.api.Test;
class MembershipServiceTest{private final MembershipService service=new MembershipService();@Test void concurrentDecisionCanOnlySucceedOnce(){UUID leader=UUID.randomUUID(),applicant=UUID.randomUUID();City city=new City(UUID.randomUUID(),"A",0,"minecraft:overworld",0,ChunkCoordinate.pack(0,0),0,leader,leader,Set.of(leader),Set.of(ChunkCoordinate.pack(0,0)));city=service.apply(city,applicant,10,true).city();var first=service.decide(city,leader,applicant,true);assertTrue(first.success());assertTrue(first.city().isMember(applicant));var second=service.decide(first.city(),leader,applicant,true);assertFalse(second.success());assertEquals(MembershipService.Failure.APPLICATION_MISSING,second.failure());}}
